mapper.sql:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopSchSql - WMS > 출고 관리 > 웨이브관리 - 생성 조회 조건 */

   AND SKU > #{edtover}


   AND PCS > #{edtover}


   AND CBM > #{edtover}


   AND WEIGHT > #{edtover}


   AND MAXLEN > #{edtover}


   AND RBRATIO > #{edtover}


   AND FBPCS > #{edtover}


   AND SKU BETWEEN #{skufr} AND #{skuto}


   AND PCS BETWEEN #{pcsfr} AND #{pcsto}


   AND CBM BETWEEN #{cbmfr} AND #{cbmto}


   AND WEIGHT BETWEEN #{weightfr} AND #{weightto}


   AND MAXLEN BETWEEN #{maxlenfr} AND #{maxlento}

mapper.select:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreateObListSku - WMS > 출고 관리 > 생성 > DAS 작업 계획 설정 > 주문 배정 주문건 조회(대,중,소)(SKU 집중화) 조회 */
SELECT CTKEY , OWKEY , OBHDKEY , CLASSIFSPECCD , RECOMBOXBARCODE , CBM AS VOL , WEIGHT , SKU AS TTICCNT , PCS AS TTICQTY , #{wahdkey} AS WAHDKEY , #{stnbarcode} AS DASSTNBARCODE FROM OB_RANK WHERE
CLASSIFSPECCD = #{spec} AND RKNO <= #{cnt}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreateObList - WMS > 출고 관리 > 웨이브관리 > 생성 > 저장 > 주문 배정 주문건 조회(대,중,소) */
SELECT CTKEY , OWKEY , OBHDKEY , CLASSIFSPECCD , RECOMBOXBARCODE , CBM AS VOL , WEIGHT , SKU AS TTICCNT , PCS AS TTICQTY , #{wahdkey} AS WAHDKEY , #{stnbarcode} AS DASSTNBARCODE FROM OB_INFO WHERE
CLASSIFSPECCD = #{spec} AND ROWNO <= #{cnt}

mapper.update:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtPopCreateObList - WMS > 출고 관리 > 웨이브관리 > 생성 > 저장 > 주문 배정 주문건 업데이트(대,중,소)  */
UPDATE TWORK_INFO_OB_HD
   SET WAHDKEY = #{wahdkey}
	  , DASSTNBARCODE = #{dasstnbarcode}
	  , UPDATEDATE = #{sysdate}
	  , UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND OBHDKEY = #{obhdkey}

mapper.select:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreateDasCell - WMS > 출고 관리 > 생성 > 저장 > 웨이브 DAS 셀 정보 조회 */ WITH CELLINFO AS (
SELECT #{item.ctkey} AS CTKEY, #{item.owkey} AS OWKEY, #{item.wahdkey} AS WAHDKEY, #{item.stnbarcode} AS STNBARCODE, #{item.classifspeccd} AS CLASSIFSPECCD, #{item.cellno} AS CELLNO
SELECT '' AS CTKEY, '' AS OWKEY, '' AS WAHDKEY, '' AS STNBARCODE, '' AS CLASSIFSPECCD, '' AS CELLNO
), CELLRSLT AS ( SELECT INFO.CTKEY , INFO.OWKEY , INFO.WAHDKEY , INFO.STNBARCODE , STC.CELLBARCODE , INFO.CLASSIFSPECCD , INFO.CELLNO , ROW_NUMBER() OVER(PARTITION BY STC.CTKEY, STC.STNBARCODE, INFO.CLASSIFSPECCD ORDER BY STC.GRPNO ASC, COALESCE(CAST(STC.PRINO AS NUMERIC), 99) ASC, CAST(STC.CELLNO AS NUMERIC) ASC) AS ROWNO FROM CELLINFO INFO INNER JOIN TWORK_MST_STNWKCELL STC ON INFO.CTKEY = STC.CTKEY AND INFO.STNBARCODE = STC.STNBARCODE AND INFO.CELLNO = (STC.DIRTDIVCD || STC.CELLNO) ) SELECT CTKEY , OWKEY , WAHDKEY , STNBARCODE , CELLBARCODE , CLASSIFSPECCD , CELLNO , ROWNO AS PRINO FROM CELLRSLT

mapper.sql:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopRbSql - WMS > 출고 관리 > 생성 > 로봇합포 작업 계획 설정 > 로봇합포 출고 대상 SQL */ WITH OB_BASE AS ( SELECT OH.CTKEY , OH.OWKEY , OH.OBHDKEY , OH.CBM , (OH.WEIGHT / 1000) AS WEIGHT , OH.CLASSIFSPECCD , OH.RECOMBOXBARCODE , (CASE BOX.BOXDIVCD WHEN '10' THEN BOX.BOXNM ELSE '그외' END) BOXNM , OH.ORDSEPTYPECD , IC.ROBSORTERICYN , GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) AS MAXLEN , OD.OBDTKEY , OD.ICKEY , OD.EXPCTQTY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD INNER JOIN TWORK_MST_BOX BOX ON OH.CTKEY = BOX.CTKEY AND OH.RECOMBOXBARCODE = BOX.BOXBARCODE WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = #{owkey} AND OH.WKTYPECD = 'RW' AND OH.WAHDKEY IS NULL AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.OBHDDAY BETWEEN #{obhddayfr} AND #{obhddayto} ), RB_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY RB_BOXNM, RB_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS RB_OBHDKEY /*릴리즈코드*/ , BOXNM AS RB_BOXNM , CBM , WEIGHT , ROW_NUMBER() OVER (ORDER BY CTKEY) AS RNO , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '30' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), RB_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.RB_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM ), RB_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.RB_OBHDKEY , HD.RB_BOXNM , IR.ICKEY , IR.ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' INNER JOIN RB_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.RB_BOXNM = IR.RB_BOXNM ), RB_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM RB_HD_MATCH GROUP BY CTKEY, OWKEY, RB_BOXNM, RB_OBHDKEY ) OB INNER JOIN RB_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.RB_OBHDKEY = OBINFO.RB_OBHDKEY AND OB.RB_BOXNM = OBINFO.RB_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_RB AS ( SELECT OB.CTKEY , OB.OWKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS AS RB_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM RB_OB_RANK
FROM RB_OB_INFO
WHERE 1=1
(RB_BOXNM = #{item.boxnm} AND RK <= #{item.noCellSet})
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OB.CTKEY , OB.OWKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS , OB.OBDT_CNT , OB.RK ), MX_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MX_BOXNM, MX_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS MX_OBHDKEY /*릴리즈코드*/ , BOXNM AS MX_BOXNM , CBM , WEIGHT , ROW_NUMBER() OVER (ORDER BY CTKEY) AS RNO , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '40' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), MX_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.MX_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM ), MX_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.MX_OBHDKEY , HD.MX_BOXNM , IR.ICKEY , IR.ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' INNER JOIN MX_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.MX_BOXNM = IR.MX_BOXNM ), MX_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM MX_HD_MATCH GROUP BY CTKEY, OWKEY, MX_BOXNM, MX_OBHDKEY ) OB INNER JOIN MX_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.MX_OBHDKEY = OBINFO.MX_OBHDKEY AND OB.MX_BOXNM = OBINFO.MX_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_MX AS ( SELECT OB.CTKEY , OB.OWKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS AS MX_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM MX_OB_RANK
FROM MX_OB_INFO
WHERE 1=1
(MX_BOXNM = #{item.boxnm} AND RK <= #{item.fbCellSet})
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OB.CTKEY , OB.OWKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS , OB.OBDT_CNT , OB.RK ), OB_MX_RB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_RB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS AS MX_RB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'Y' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS , MX.OBDT_CNT , MX.RK ), OB_MX_FB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_FB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS AS MX_FB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'N' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS , MX.OBDT_CNT , MX.RK )

mapper.select:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreateSimpleObListSku - WMS > 출고 관리 > 생성 > 저장 > 단포 작업 계획 설정 > 단포 주문 배정 주문건 조회(SKU 집중화) 조회 */
SELECT CTKEY , OWKEY , OBHDKEY , CLASSIFSPECCD , RECOMBOXBARCODE , CBM AS VOL , WEIGHT , SKU AS TTICCNT , PCS AS TTICQTY , #{wahdkey} AS WAHDKEY FROM OB_RANK WHERE 1=1
AND RKNO <= #{sObCnt}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreateSimpleObList - WMS > 출고 관리 > 생성 > 저장 > 단포 작업 계획 설정 > 단포 주문 배정 주문건 조회 조회 */
SELECT CTKEY , OWKEY , OBHDKEY , CLASSIFSPECCD , RECOMBOXBARCODE , CBM AS VOL , WEIGHT , SKU AS TTICCNT , PCS AS TTICQTY , #{wahdkey} AS WAHDKEY FROM IC_INFO WHERE 1=1
AND ROWNO <= #{sObCnt}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectobWaveMgmtPopCreateWaHdWarnd - WMS > 출고 관리 > 생성 > 저장 > 웨이브 헤더 회차 조회 */
SELECT COALESCE(MAX(TO_NUMBER(COALESCE(WARND, 0))), 0) + 1 AS WARND
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDDAY = #{wahdday}

		/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectobWaveMgmtPopWaHdDlvrycorpcd - WMS > 출고 관리 > 생성 > 웨이브의 릴리즈코드 중 택배접수가 된 건의 택배사코드 조회 */
		SELECT DLVRYCORPCD
		  FROM TWORK_INFO_OB_HD
		 WHERE CTKEY = #{ctkey}
		   AND OWKEY = #{owkey}
		   AND WAHDKEY = #{wahdkey}
		   AND DLVRYCORPCD IS NOT NULL

LIMIT 1

mapper.update:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtPopWaHdDlvrycorpcd - WMS > 출고 관리 > 생성 > 웨이브헤더 택배사코드 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET DLVRYCORPCD = #{dlvrycorpcd}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtWkClassObHdMapping - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 릴리즈 헤더에 CELL_BARCODE 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET DASCELLBARCODE = #{cellbarcode}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtWkClassDasCellMapping - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - DAS CELL에 릴리즈코드 업데이트 */
UPDATE TWORK_INFO_WA_DAS_CELL
   SET OBHDKEY = #{obhdkey}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND STNBARCODE = #{dasstnbarcode}
   AND CELLBARCODE = #{cellbarcode}

mapper.insert:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateobWaveMgmtWkClassRbYN - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 상품 마스터 로봇 소터여부 조회 */
UPDATE TWORK_INFO_OB_DT
   SET ROBSORTERICYN = #{robsortericyn}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

mapper.update:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtWkClassSendWaHd - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 웨이브 헤더에 분류계획 전송여부 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET CLASSIFPLANSNDYN = 'Y'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

mapper.select:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtClassList - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 중분류 셀 정보 조회 */
SELECT LC.MDLCLASSIFCELLBARCODE
  FROM TWORK_INFO_WA_HD WH
 INNER JOIN TWORK_INFO_WA_DAS_STN_LC LC
	ON WH.CTKEY = LC.CTKEY
   AND WH.OWKEY = LC.OWKEY
   AND WH.WAHDKEY = LC.WAHDKEY
 WHERE WH.CTKEY = #{ctkey}
   AND WH.OWKEY = #{owkey}
   AND WH.WAHDKEY = #{wahdkey}
   AND WH.WKTYPECD IN ('DW')
   AND LC.STNBARCODE = #{stnbarcode}

mapper.update:
/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateObWaveMgmtWkClassDasSendWaHd - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 웨이브 헤더에 로케이션계획전송여부 전송여부 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET LOCPLANSNDYN = 'Y'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateWaveMgmtPopInfo_T01_Add_WaAddProcObHd - WMS > 출고 관리 > 웨이브관리 > 웨이브 정보 상세 > 출고 계획 > 추가 - 릴리즈 헤더에 WAVE 공통코드, 스테이션 바코드 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET WAHDKEY = #{wahdkey}
	 , DASSTNBARCODE = #{stnbarcode}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - updateWaveMgmtPopInfo_T01_Add_WaAddProcWaDt - WMS > 출고 관리 > 웨이브관리 > 웨이브 정보 상세 > 출고 계획 > 추가 - 웨이브 상세 데이터 업데이트 */
UPDATE TWORK_INFO_WA_DT
   SET DELYN = 'N'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND OBHDKEY = #{obhdkey}

mapper.delete:
