/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectObWaveMgmtPopCreaDasCell - WMS > 출고 관리 > 생성 > 저장 > 웨이브 DAS 셀 정보 조회 */ WITH CELLINFO AS (
SELECT #{item.ctkey} AS CTKEY, #{item.owkey} AS OWKEY, #{item.wahdkey} AS WAHDKEY, #{item.stnbarcode} AS STNBARCODE, #{item.classifspeccd} AS CLASSIFSPECCD, #{item.cellno} AS CELLNO
SELECT '' AS CTKEY, '' AS OWKEY, '' AS WAHDKEY, '' AS STNBARCODE, '' AS CLASSIFSPECCD, '' AS CELLNO
), CELLRSLT AS ( SELECT INFO.CTKEY , INFO.OWKEY , INFO.WAHDKEY , INFO.STNBARCODE , STC.CELLBARCODE , INFO.CLASSIFSPECCD , INFO.CELLNO , ROW_NUMBER() OVER(PARTITION BY STC.CTKEY, STC.STNBARCODE, INFO.CLASSIFSPECCD ORDER BY STC.GRPNO ASC, COALESCE(CAST(STC.PRINO AS NUMERIC), 99) ASC, CAST(STC.CELLNO AS NUMERIC) ASC) AS ROWNO FROM CELLINFO INFO INNER JOIN TWORK_MST_STNWKCELL STC ON INFO.CTKEY = STC.CTKEY AND INFO.STNBARCODE = STC.STNBARCODE AND INFO.CELLNO = (STC.DIRTDIVCD || STC.CELLNO) ) SELECT CTKEY , OWKEY , WAHDKEY , STNBARCODE , CELLBARCODE , CLASSIFSPECCD , CELLNO , ROWNO AS PRINO FROM CELLRSLT

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectobWaveMgmtPopCreWaHdWarnd - WMS > 출고 관리 > 생성 > 저장 > 웨이브 헤더 회차 조회 */
